SELECT '전체신청' AS "gbn" , COALESCE(SUM(1), 0) AS "all" , COALESCE(SUM(CASE mm WHEN '01' THEN 1 ELSE 0 END), 0) AS "jan" , COALESCE(SUM(CASE mm WHEN '02' THEN 1 ELSE 0 END), 0) AS "feb" , COALESCE(SUM(CASE mm WHEN '03' THEN 1 ELSE 0 END), 0) AS "mar" , COALESCE(SUM(CASE mm WHEN '04' THEN 1 ELSE 0 END), 0) AS "apr" , COALESCE(SUM(CASE mm WHEN '05' THEN 1 ELSE 0 END), 0) AS "may" , COALESCE(SUM(CASE mm WHEN '06' THEN 1 ELSE 0 END), 0) AS "jun" , COALESCE(SUM(CASE mm WHEN '07' THEN 1 ELSE 0 END), 0) AS "jul" , COALESCE(SUM(CASE mm WHEN '08' THEN 1 ELSE 0 END), 0) AS "aug" , COALESCE(SUM(CASE mm WHEN '09' THEN 1 ELSE 0 END), 0) AS "sep" , COALESCE(SUM(CASE mm WHEN '10' THEN 1 ELSE 0 END), 0) AS "oct" , COALESCE(SUM(CASE mm WHEN '11' THEN 1 ELSE 0 END), 0) AS "nov" , COALESCE(SUM(CASE mm WHEN '12' THEN 1 ELSE 0 END), 0) AS "dec" FROM ( SELECT mgr_seq , use_rs_cd , substring(reqst_dat, 1, 4) AS yy , substring(reqst_dat, 5, 2) AS mm FROM xeus.crms_trans_rqst
req_gbn_cd <> '15'
AND req_gbn_cd = #{reqGbnCd}
AND reqst_dat LIKE #{year}||'%'
) AS r
UNION ALL
SELECT '미입력' AS "gbn" , COALESCE(SUM(1), 0) AS "all" , COALESCE(SUM(CASE mm WHEN '01' THEN 1 ELSE 0 END), 0) AS "jan" , COALESCE(SUM(CASE mm WHEN '02' THEN 1 ELSE 0 END), 0) AS "feb" , COALESCE(SUM(CASE mm WHEN '03' THEN 1 ELSE 0 END), 0) AS "mar" , COALESCE(SUM(CASE mm WHEN '04' THEN 1 ELSE 0 END), 0) AS "apr" , COALESCE(SUM(CASE mm WHEN '05' THEN 1 ELSE 0 END), 0) AS "may" , COALESCE(SUM(CASE mm WHEN '06' THEN 1 ELSE 0 END), 0) AS "jun" , COALESCE(SUM(CASE mm WHEN '07' THEN 1 ELSE 0 END), 0) AS "jul" , COALESCE(SUM(CASE mm WHEN '08' THEN 1 ELSE 0 END), 0) AS "aug" , COALESCE(SUM(CASE mm WHEN '09' THEN 1 ELSE 0 END), 0) AS "sep" , COALESCE(SUM(CASE mm WHEN '10' THEN 1 ELSE 0 END), 0) AS "oct" , COALESCE(SUM(CASE mm WHEN '11' THEN 1 ELSE 0 END), 0) AS "nov" , COALESCE(SUM(CASE mm WHEN '12' THEN 1 ELSE 0 END), 0) AS "dec" FROM ( SELECT mgr_seq , use_rs_cd , substring(reqst_dat, 1, 4) AS yy , substring(reqst_dat, 5, 2) AS mm FROM xeus.crms_trans_rqst
