SELECT (SELECT cde_nm FROM xeus.mt_cmm_cde AS code WHERE code.grp_cde = 'C55' AND code.cde_cde = use_rs_cd ) AS "gbn" , COALESCE(SUM(1), 0) AS "all" , COALESCE(SUM(CASE mm WHEN '01' THEN 1 ELSE 0 END), 0) AS "jan" , COALESCE(SUM(CASE mm WHEN '02' THEN 1 ELSE 0 END), 0) AS "feb" , COALESCE(SUM(CASE mm WHEN '03' THEN 1 ELSE 0 END), 0) AS "mar" , COALESCE(SUM(CASE mm WHEN '04' THEN 1 ELSE 0 END), 0) AS "apr" , COALESCE(SUM(CASE mm WHEN '05' THEN 1 ELSE 0 END), 0) AS "may" , COALESCE(SUM(CASE mm WHEN '06' THEN 1 ELSE 0 END), 0) AS "jun" , COALESCE(SUM(CASE mm WHEN '07' THEN 1 ELSE 0 END), 0) AS "jul" , COALESCE(SUM(CASE mm WHEN '08' THEN 1 ELSE 0 END), 0) AS "aug" , COALESCE(SUM(CASE mm WHEN '09' THEN 1 ELSE 0 END), 0) AS "sep" , COALESCE(SUM(CASE mm WHEN '10' THEN 1 ELSE 0 END), 0) AS "oct" , COALESCE(SUM(CASE mm WHEN '11' THEN 1 ELSE 0 END), 0) AS "nov" , COALESCE(SUM(CASE mm WHEN '12' THEN 1 ELSE 0 END), 0) AS "dec" FROM ( SELECT mgr_seq , use_rs_cd , substring(reqst_dat, 1, 4) AS yy , substring(reqst_dat, 5, 2) AS mm FROM xeus.crms_trans_rqst
req_gbn_cd <> '15'
AND req_gbn_cd = #{reqGbnCd}
AND reqst_dat LIKE #{year}||'%'
) AS r WHERE use_rs_cd NOT IN ('11') GROUP BY use_rs_cd

SELECT * FROM ( SELECT '총계' AS "gbn" , COALESCE(SUM(1), 0) AS "all" , COALESCE(SUM(CASE mm WHEN '01' THEN 1 ELSE 0 END), 0) AS "jan" , COALESCE(SUM(CASE mm WHEN '02' THEN 1 ELSE 0 END), 0) AS "feb" , COALESCE(SUM(CASE mm WHEN '03' THEN 1 ELSE 0 END), 0) AS "mar" , COALESCE(SUM(CASE mm WHEN '04' THEN 1 ELSE 0 END), 0) AS "apr" , COALESCE(SUM(CASE mm WHEN '05' THEN 1 ELSE 0 END), 0) AS "may" , COALESCE(SUM(CASE mm WHEN '06' THEN 1 ELSE 0 END), 0) AS "jun" , COALESCE(SUM(CASE mm WHEN '07' THEN 1 ELSE 0 END), 0) AS "jul" , COALESCE(SUM(CASE mm WHEN '08' THEN 1 ELSE 0 END), 0) AS "aug" , COALESCE(SUM(CASE mm WHEN '09' THEN 1 ELSE 0 END), 0) AS "sep" , COALESCE(SUM(CASE mm WHEN '10' THEN 1 ELSE 0 END), 0) AS "oct" , COALESCE(SUM(CASE mm WHEN '11' THEN 1 ELSE 0 END), 0) AS "nov" , COALESCE(SUM(CASE mm WHEN '12' THEN 1 ELSE 0 END), 0) AS "dec" FROM( SELECT org.org_nm , substring(reqst_dat, 1, 4) AS yy , substring(reqst_dat, 5, 2) AS mm , substring(reqst_dat, 7, 2) AS dd FROM xeus.crms_trans_rqst as rqst, xeus.mt_usr_desc as usr, xeus.mt_orgz_desc as org
req_gbn_cd <> '15'
AND req_gbn_cd = #{reqGbnCd}
AND reqst_dat LIKE #{year}||'%'
AND rqst.reqst_id = usr.user_id AND usr.org_mgr_no = org.org_mgr_no
) AS r
UNION ALL
SELECT org_nm AS "gbn" , COALESCE(SUM(1), 0) AS "all" , COALESCE(SUM(CASE mm WHEN '01' THEN 1 ELSE 0 END), 0) AS "jan" , COALESCE(SUM(CASE mm WHEN '02' THEN 1 ELSE 0 END), 0) AS "feb" , COALESCE(SUM(CASE mm WHEN '03' THEN 1 ELSE 0 END), 0) AS "mar" , COALESCE(SUM(CASE mm WHEN '04' THEN 1 ELSE 0 END), 0) AS "apr" , COALESCE(SUM(CASE mm WHEN '05' THEN 1 ELSE 0 END), 0) AS "may" , COALESCE(SUM(CASE mm WHEN '06' THEN 1 ELSE 0 END), 0) AS "jun" , COALESCE(SUM(CASE mm WHEN '07' THEN 1 ELSE 0 END), 0) AS "jul" , COALESCE(SUM(CASE mm WHEN '08' THEN 1 ELSE 0 END), 0) AS "aug" , COALESCE(SUM(CASE mm WHEN '09' THEN 1 ELSE 0 END), 0) AS "sep" , COALESCE(SUM(CASE mm WHEN '10' THEN 1 ELSE 0 END), 0) AS "oct" , COALESCE(SUM(CASE mm WHEN '11' THEN 1 ELSE 0 END), 0) AS "nov" , COALESCE(SUM(CASE mm WHEN '12' THEN 1 ELSE 0 END), 0) AS "dec" FROM( SELECT org.org_nm , substring(reqst_dat, 1, 4) AS yy , substring(reqst_dat, 5, 2) AS mm , substring(reqst_dat, 7, 2) AS dd FROM xeus.crms_trans_rqst as rqst, xeus.mt_usr_desc as usr, xeus.mt_orgz_desc as org
req_gbn_cd <> '15'
AND req_gbn_cd = #{reqGbnCd}
AND reqst_dat LIKE #{year}||'%'
AND rqst.reqst_id = usr.user_id AND usr.org_mgr_no = org.org_mgr_no
) AS r
GROUP BY org_nm ) AS A ORDER BY (CASE WHEN "gbn" = '총계' THEN 1 ELSE 2 END), "gbn" ASC;
